{
  "family": "Houben-Hoesch Reaction/Synthesis",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "COc1cc(OC)cc(OC)c1"
    ],
    "product_smiles": [
      "CC(=O)c1cc(OC)cc(OC)c1O"
    ],
    "optional_reagent_smiles": [
      "Cl[Zn]Cl",
      "Cl"
    ],
    "rationale": "This is a canonical example of the Houben-Hoesch reaction, featuring the acylation of a highly activated, electron-rich aromatic ring (1,3,5-trimethoxybenzene) with a simple nitrile (acetonitrile). The reaction is catalyzed by a Lewis acid (ZnCl2) and HCl, followed by aqueous workup to hydrolyze the intermediate ketimine, yielding the final aryl ketone product. This example clearly illustrates the key transformation: the formation of a C-C bond between an aromatic carbon and the nitrile carbon, resulting in an acyl group attached to the ring.",
    "collision_avoidance_note": "This example uses a simple, highly activated polyalkoxybenzene, which is characteristic of the Houben-Hoesch reaction's substrate scope. It avoids using simpler phenols (like phenol or resorcinol) which might overlap with the Gattermann reaction (which uses HCN or its equivalents). The use of a simple aliphatic nitrile (acetonitrile) instead of HCN or formylating agents distinguishes it from formylation reactions. The acyclic nature of the nitrile and the simple substitution pattern on the arene minimize potential collisions with intramolecular cyclization reactions or other named reactions involving more complex arenes."
  }
}
